"""Channel handlers — stub senders behind one interface.

🎙️ "The problem says handlers need not be implemented, so these are stubs.
What matters is the interface: every channel exposes the same send() method,
so the router treats them uniformly and a new channel is just a new class."
"""
from __future__ import annotations

from abc import ABC, abstractmethod

from models import Channel, DeliveryResult, Notification, User


# ── WHY THIS CLASS ──────────────────────────────────────────────────────────
# Uniform interface over different delivery vendors (Strategy/Adapter).
class ChannelHandler(ABC):
    @property
    @abstractmethod
    def channel(self) -> Channel:
        """Which channel this handler serves — used as the registry key."""
        raise NotImplementedError

    @abstractmethod
    def send(self, notification: Notification, user: User) -> DeliveryResult:
        raise NotImplementedError


class EmailHandler(ChannelHandler):
    @property
    def channel(self) -> Channel:
        return Channel.EMAIL

    def send(self, notification: Notification, user: User) -> DeliveryResult:
        # Stub — a real impl would call an email vendor. We just report success.
        return DeliveryResult(Channel.EMAIL, True, f"email -> {user.email}")


class SmsHandler(ChannelHandler):
    @property
    def channel(self) -> Channel:
        return Channel.SMS

    def send(self, notification: Notification, user: User) -> DeliveryResult:
        return DeliveryResult(Channel.SMS, True, f"sms -> {user.phone}")


class PushHandler(ChannelHandler):
    @property
    def channel(self) -> Channel:
        return Channel.PUSH

    def send(self, notification: Notification, user: User) -> DeliveryResult:
        return DeliveryResult(Channel.PUSH, True, f"push -> {user.device_token}")

"""Observers — audit/metrics decoupled from routing.

🎙️ "Observer pattern. The router notifies listeners after each dispatch, so I
can add audit logging or metrics without touching the routing logic."
"""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import List

from models import DispatchReport


class DispatchListener(ABC):
    @abstractmethod
    def on_dispatch(self, report: DispatchReport) -> None:
        raise NotImplementedError


# ── WHY THIS CLASS ──────────────────────────────────────────────────────────
# Keeps a record of every dispatch — proves the Observer seam is wired.
class AuditLogListener(DispatchListener):
    def __init__(self) -> None:
        self.log: List[DispatchReport] = []

    def on_dispatch(self, report: DispatchReport) -> None:
        self.log.append(report)
